static inline int parse_and_validate_network_header(
	struct sk_buff *skb,
	struct net_device *dev,
	unsigned char *eth_hdr,
	unsigned int *proto)
{
	if (skb->len < ETH_HLEN)
		return -EINVAL;
	*proto = ntohs(*(unsigned short *)(eth_hdr + 12));
	if (*proto < 1536 && skb->len < (*proto + ETH_HLEN))
		return -EINVAL;
	return 0;
}
